function i(n){return String(n||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toUpperCase().replace(/\s+/g," ").trim()}function t(n){let e=i(n);return e?e.includes("ORANGE DIGITAL KALANSO")||e.includes("ODK")||e.includes("ORANGE DIGITAL MULTIMEDIA")||e.includes("MULTIMEDIA")||e.includes("ORANGE FABLAB")||e.includes("FABLAB")||e.includes("ORANGE FAB"):!1}function c(n){return n.filter(e=>t(e?.nom))}function u(n){let e=i(n);return e?e.includes("DCIRE")?!0:e.replace(/-/g," ").includes("DCI RE"):!1}export{t as a,c as b,u as c};
